//stack-extent.js

import { StackLayout } from './stack-layout';

var proto = StackLayout.prototype;

/**
 * @return {Boolean} [description]
 */
proto.getAllExtents = function() {
    var layout = this;

    if (layout._keyExtents) {
        return layout._keyExtents;
    }

    var list = layout._list,
        extents = [],
        getObj = (val, d) => {
            let _ = [val.key, d];
            _.sum = (val[0] || 0) + (val[1] || 0);
            return _;
        };

    list.each(val => {
        // Positive
        if (val[1] >= 0) {
            extents.push(getObj(val, val[1]));
        }

        // Negative
        if (val[0] < 0) {
            extents.push(getObj(val, val[0]));
        }
    });
    return (layout._keyExtents = extents);
};
